import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6903_巨漢/20260502/G11_戰略規劃與新業務展望_產品趨勢研究員.md","filePath":"審計報告庫/經營審計/6903_巨漢/20260502/G11_戰略規劃與新業務展望_產品趨勢研究員.md"}'),_={name:"審計報告庫/經營審計/6903_巨漢/20260502/G11_戰略規劃與新業務展望_產品趨勢研究員.md"};function i(l,a,n,s,h,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>戰略規劃與新業務展望</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢成長策略為「AI 基礎建設 + 公共工程」雙引擎。在手訂單 116 億（3-4 年能見度）。海外佈局已宣布赴美設分公司。AI 相關營收預估 2026 年達 60%。策略方向正確但無突破性，第二成長曲線仍在初期。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B+。AI 需求明確、在手訂單充足。利空：海外布局進度不明，尚無具體客戶或訂單。公共工程毛利率通常低於半導體業，若佔比提高將壓縮獲利。公司缺乏明確的 M&amp;A 策略。管理層年齡偏高（創辦人 70+），接班後的策略能否延續是未知數。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>巨漢策略雙引擎：①AI 基礎建設（晶圓代工、先進封裝、AI 算力中心）—目前在手訂單以半導體廠務為主，116 億訂單中 AI 相關估 60%+，2026 年 AI 營收佔比目標突破 60%；②公共工程（交通部鐵道局等）—毛利率較低但案源穩定，有助分散景氣風險。海外布局：已宣布赴美設分公司跟進客戶（台積電等）海外設廠需求，但尚未揭露具體時程和投資金額。短期內海外營收貢獻有限，主要成長動能仍來自台灣半導體擴產需求。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>成長天花板風險</strong>：AI 基礎建設需求強勁但半導體景氣週期性強。若全球半導體資本支出反轉，巨漢營收可能斷崖式下滑（2026 年成長率將從 2025 年的 +72.8% 大幅放緩）。</li><li><strong>海外布局是必要但高風險</strong>：赴美設分公司是跟隨客戶需求，但美國建廠成本高、法規複雜，初期可能虧損。若管理不善將拖累整體獲利。</li><li><strong>接班策略不明</strong>：創辦人年事已高，交班後的策略方向能否延續是重大不確定因素。羅瑞鴻（總經理）能否獨立主導策略？若創辦人退休後策略轉向保守，成長動能將進一步放緩。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><p>web_search：巨漢法說會重點、營運展望</p>',12)])])}const u=e(_,[["render",i]]);export{p as __pageData,u as default};
